// Susun transcript jadi teks untuk LLM.
const body = $json.body || $json;
const t = Array.isArray(body.transcript) ? body.transcript : [];
const lines = t.map(m => `${(m.role||'').toUpperCase()}: ${m.content||''}`).join('\n');
const today = new Date().toLocaleDateString('id-ID', { day:'2-digit', month:'2-digit', year:'numeric' });
return [{ json: {
  conversationId: body.conversationId || '',
  nama: body.clientName || '',
  phone: body.phone || '',
  channel: body.channel || 'whatsapp',
  tanggal: today,
  transcriptText: lines || '(tidak ada pesan)'
} }];

