// Parse JSON dari Gemini + lengkapi field identitas dari Build Prompt.
const base = $('Build Prompt').first().json;
let out = {};
try {
  const content = $json.candidates[0].content.parts[0].text;
  out = JSON.parse(content);
} catch (e) {
  out = { ringkasan: 'Gagal parse output AI', status: 'Cold' };
}
return [{ json: {
  conversationId: base.conversationId,
  tanggal: out.tanggal || base.tanggal,
  nama: out.nama || base.nama,
  phone: out.phone || base.phone,
  channel: out.channel || base.channel,
  project_type: out.project_type || '',
  lokasi: out.lokasi || '',
  luas_m2: out.luas_m2 ?? '',
  estimasi_value: out.estimasi_value ?? '',
  status: out.status || 'Cold',
  design_stage: out.design_stage || '-',
  progress_pct: out.progress_pct ?? 0,
  ringkasan: out.ringkasan || ''
} }];
